t.script:

var selectedProviderId   = null;
var selectedProviderCode = null;
var stripe               = null;
var stripeCard           = null;

function selectProvider(el) {
    // Reset all cards
    document.querySelectorAll('[data-provider-id]').forEach(function(e) {
        e.style.borderColor = '#e0e0e0';
        e.style.background  = 'white';
    });

    // Highlight selected
    el.style.borderColor = '#875A7B';
    el.style.background  = '#fdf6ff';

    selectedProviderId   = parseInt(el.getAttribute('data-provider-id'));
    selectedProviderCode = el.getAttribute('data-provider-code');
    var providerKey      = el.getAttribute('data-provider-key') || '';

    var stripeContainer = document.getElementById('stripe-card-container');

    if (selectedProviderCode === 'stripe') {
        stripeContainer.style.display = 'block';

        // Init Stripe Elements only once
        if (!stripe) {
            var pubKey = providerKey || document.getElementById('hid-stripe-key').value;
            if (!pubKey) {
                document.getElementById('stripe-card-errors').textContent =
                    'Stripe publishable key not configured.';
                return;
            }
            stripe = Stripe(pubKey);
            var elements = stripe.elements();
            stripeCard = elements.create('card', {
                hidePostalCode: true,
                style: {
                    base: {
                        fontSize: '16px',
                        color: '#333333',
                        fontFamily: 'Arial, sans-serif',
                        '::placeholder': { color: '#aaaaaa' }
                    },
                    invalid: { color: '#e74c3c' }
                }
            });
            stripeCard.mount('#stripe-card-element');
            stripeCard.on('change', function(event) {
                document.getElementById('stripe-card-errors').textContent =
                    event.error ? event.error.message : '';
            });
        }
    } else {
        stripeContainer.style.display = 'none';
    }
}

async function submitPayment() {
    if (!selectedProviderId) {
        alert('Please select a payment method.');
        return;
    }

    var btn = document.getElementById('pay-btn');
    btn.disabled    = true;
    btn.textContent = 'Processing...';

    var invoiceId   = parseInt(document.getElementById('hid-invoice-id').value);
    var amount      = parseFloat(document.getElementById('hid-amount').value);
    var currencyId  = parseInt(document.getElementById('hid-currency-id').value);
    var partnerId   = parseInt(document.getElementById('hid-partner-id').value);
    var accessToken = document.getElementById('hid-access-token').value;

    try {
        // ── Step 1: Create transaction on server ──────────
        var response = await fetch('/rental/pay/create-transaction', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method:  'call',
                id:      1,
                params: {
                    invoice_id:  invoiceId,
                    access_token: accessToken,
                    provider_id: selectedProviderId,
                }
            })
        });

        var data   = await response.json();
        var result = data.result;

        if (!result || result.error) {
            throw new Error(result && result.error ? result.error : 'Transaction creation failed');
        }

        // ── Step 2: Handle by provider ────────────────────
        if (selectedProviderCode === 'stripe') {

            if (!result.client_secret) {
                throw new Error('Stripe client secret not received. Check Stripe API keys.');
            }

            // Confirm card payment via Stripe.js
            var confirmResult = await stripe.confirmCardPayment(
                result.client_secret,
                { payment_method: { card: stripeCard } }
            );

            if (confirmResult.error) {
                throw new Error(confirmResult.error.message);
            }

            // ── Step 3: Notify Odoo that payment succeeded ─
            await fetch('/rental/pay/stripe-confirm', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method:  'call',
                    id:      1,
                    params: {
                        tx_id:              result.tx_id,
                        access_token:       accessToken,
                        payment_intent_id:  confirmResult.paymentIntent.id,
                    }
                })
            });

            // ── Step 4: Redirect to status page ───────────
            window.location.href = '/rental/pay/status?tx_id='
                + result.tx_id + '&access_token=' + accessToken;

        } else if (result.redirect_url) {
            window.location.href = result.redirect_url;

        } else {
            window.location.href = '/rental/pay/status?tx_id='
                + result.tx_id + '&access_token=' + accessToken;
        }

    } catch(e) {
        document.getElementById('stripe-card-errors').textContent = e.message || 'Payment failed.';
        alert('Payment error: ' + (e.message || 'Unknown error'));
        btn.disabled    = false;
        btn.textContent = 'Pay';
    }
}

